import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# C++ kernel代码
cpp_source = """
#include <torch/extension.h>
#include <immintrin.h>  // AVX2/AVX-512 intrinsics
#include <cmath>
#include <algorithm>
#include <omp.h>

// ========== 内联的高性能 kernel 实现 ==========

// 向量化的矩阵乘法辅助函数: 计算A的第i行和B的第j行的点积（A,B都按行存储）
// 使用AVX2（256位，8个float）进行向量化
inline float vec_dot_product_avx2(const float* a_row, const float* b_row, int64_t D) {
    constexpr int VEC_SIZE = 8;  // AVX2: 8个float32
    __m256 sum_vec = _mm256_setzero_ps();

    // 向量化部分
    for (int64_t k = 0; k + VEC_SIZE <= D; k += VEC_SIZE) {
        __m256 a_vec = _mm256_loadu_ps(&a_row[k]);
        __m256 b_vec = _mm256_loadu_ps(&b_row[k]);
        // 乘积累加：a*b + sum
        sum_vec = _mm256_fmadd_ps(a_vec, b_vec, sum_vec);
    }

    // 水平求和
    float sum_arr[VEC_SIZE];
    _mm256_storeu_ps(sum_arr, sum_vec);
    float sum = sum_arr[0] + sum_arr[1] + sum_arr[2] + sum_arr[3] + 
                sum_arr[4] + sum_arr[5] + sum_arr[6] + sum_arr[7];

    // 处理剩余元素（标量fallback）
    int64_t remaining_start = (D / VEC_SIZE) * VEC_SIZE;
    for (int64_t k = remaining_start; k < D; ++k) {
        sum += a_row[k] * b_row[k];
    }

    return sum;
}

// softmax的数值稳定版本，对一行数据进行向量化计算
inline void stable_softmax_row(float* row, int64_t length) {
    // 1. 找最大值（数值稳定性）
    float max_val = row[0];
    for (int64_t i = 1; i < length; ++i) {
        if (row[i] > max_val) {
            max_val = row[i];
        }
    }

    // 2. 计算指数并求和
    float sum = 0.0f;
    for (int64_t i = 0; i < length; ++i) {
        // 先减去最大值，防止指数溢出
        float exp_val = std::exp(row[i] - max_val);
        row[i] = exp_val;
        sum += exp_val;
    }

    // 3. 归一化
    if (sum > 0.0f) {
        float inv_sum = 1.0f / sum;
        for (int64_t i = 0; i < length; ++i) {
            row[i] *= inv_sum;
        }
    }
}

// 主kernel实现：Scaled Dot-Product Attention (小批量baseline版本)
torch::Tensor akg_cache_attention_small_baseline_kernel(
    torch::Tensor query, 
    torch::Tensor key, 
    torch::Tensor value, 
    float sm_scale
) {
    // 1. 参数验证和准备
    TORCH_CHECK(query.device().is_cpu(), "Input tensors must be on CPU");
    TORCH_CHECK(query.dim() == 4 && key.dim() == 4 && value.dim() == 4, 
                "All input tensors must have 4 dimensions");
    TORCH_CHECK(query.size(0) == key.size(0) && key.size(0) == value.size(0),
                "Batch sizes must match");
    TORCH_CHECK(query.size(1) == key.size(1) && key.size(1) == value.size(1),
                "Head counts must match");
    TORCH_CHECK(query.size(2) == key.size(2) && key.size(2) == value.size(2),
                "Sequence lengths must match");
    TORCH_CHECK(query.size(3) == key.size(3) && key.size(3) == value.size(3),
                "Feature dimensions must match");

    // 确保张量是连续的
    if (!query.is_contiguous()) query = query.contiguous();
    if (!key.is_contiguous()) key = key.contiguous();
    if (!value.is_contiguous()) value = value.contiguous();

    // 获取形状参数
    int64_t B = query.size(0);  // batch size
    int64_t H = query.size(1);  // head count
    int64_t L = query.size(2);  // sequence length
    int64_t D = query.size(3);  // feature dimension per head

    // 2. 创建输出张量
    auto output = torch::zeros({B, H, L, D}, query.options());

    // 获取数据指针
    auto q_ptr = query.data_ptr<float>();
    auto k_ptr = key.data_ptr<float>();
    auto v_ptr = value.data_ptr<float>();
    auto out_ptr = output.data_ptr<float>();

    // 3. 使用OpenMP并行化批次和头维度
    #pragma omp parallel for collapse(2)
    for (int64_t b = 0; b < B; ++b) {
        for (int64_t h = 0; h < H; ++h) {
            // 计算当前头在内存中的偏移
            int64_t bh_offset = (b * H + h) * L * D;
            const float* q_bh = q_ptr + bh_offset;
            const float* k_bh = k_ptr + bh_offset;
            const float* v_bh = v_ptr + bh_offset;
            float* out_bh = out_ptr + bh_offset;

            // 临时存储注意力分数矩阵 [L x L]
            float* attn_scores = new float[L * L];

            // 4. 计算注意力分数矩阵：Q @ K^T
            for (int64_t i = 0; i < L; ++i) {
                for (int64_t j = 0; j < L; ++j) {
                    // 计算Q[i]和K[j]的点积
                    float dot = vec_dot_product_avx2(
                        q_bh + i * D,  // Q的第i行
                        k_bh + j * D,  // K的第j行（转置后）
                        D
                    );
                    // 应用缩放
                    attn_scores[i * L + j] = dot * sm_scale;
                }
            }

            // 5. 对每一行进行softmax
            for (int64_t i = 0; i < L; ++i) {
                stable_softmax_row(&attn_scores[i * L], L);
            }

            // 6. 计算输出：attn @ V
            for (int64_t i = 0; i < L; ++i) {
                for (int64_t d = 0; d < D; ++d) {
                    float sum = 0.0f;
                    for (int64_t j = 0; j < L; ++j) {
                        sum += attn_scores[i * L + j] * v_bh[j * D + d];
                    }
                    out_bh[i * D + d] = sum;
                }
            }

            // 清理临时内存
            delete[] attn_scores;
        }
    }

    return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("akg_cache_attention_small_baseline_kernel", 
          &akg_cache_attention_small_baseline_kernel, 
          "CPU implementation of scaled dot-product attention (small baseline)");
}
"""

# 动态加载C++扩展，启用OpenMP和AVX2优化
akg_cache_attention_module = load_inline(
    name="akg_cache_attention_small_baseline",
    cpp_sources=cpp_source,
    extra_cflags=["-O3", "-mavx2", "-mfma", "-fopenmp"],
    extra_ldflags=["-fopenmp"],
    verbose=True
)

class ModelNew(nn.Module):
    def __init__(self, sm_scale):
        super().__init__()
        self.sm_scale = sm_scale  # 从get_init_inputs获取的scale参数

    def forward(self, query: torch.Tensor, key: torch.Tensor, value: torch.Tensor) -> torch.Tensor:
        # 确保输入在CPU上
        if query.device.type != "cpu":
            query = query.cpu()
            key = key.cpu()
            value = value.cpu()

        # 从输入张量获取shape参数
        B, H, L, D = query.shape  # 变量名与get_inputs构造时保持一致

        # 调用C++ kernel实现scaled dot-product attention
        # sm_scale作为硬编码参数传入（来自__init__）
        return akg_cache_attention_module.akg_cache_attention_small_baseline_kernel(
            query, key, value, self.sm_scale
        )

